        // 其他原有配置不变
      },
      {
        "id": "productmanager-agent",
        "responsePrefix": "📝 【产品经理】",
        // 其他原有配置不变
      },
      {
        "id": "dataanalyst-agent",
        "responsePrefix": "📊 【数据分析师】",
        // 其他原有配置不变
      }
    ]
  }
}
```
